// figma-import-register.js
// 新規登録画面を Figma に追加します。

(async () => {
  const IMG_REGISTER = "data:image/png;base64,";

  // 02_新規登録
  const frame = figma.createFrame();
  frame.name = "02_新規登録";
  frame.resize(1440, 900);
  frame.x = 0;
  frame.y = 0;
  const imgData_register = IMG_REGISTER.replace(/^data:image\/png;base64,/, "");
  const bytes_register = Uint8Array.from(atob(imgData_register), c => c.charCodeAt(0));
  const img_register = figma.createImage(bytes_register);
  frame.fills = [{ type: "IMAGE", scaleMode: "FILL", imageHash: img_register.hash }];

  figma.currentPage.selection = [frame];
  figma.viewport.scrollAndZoomIntoView([frame]);
  figma.closePlugin("✅ 02_新規登録 をFigmaに追加しました！");
})();
